{
  "name": "OmniTrace Intelligence",
  "description": "An advanced phone intelligence and digital forensic dashboard for OSINT-based number verification, carrier tracing, and reputation analysis.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

export interface GroundingChunk {
  web?: {
    uri: string;
    title: string;
  };
}

export interface IntelligenceReport {
  phoneNumber: string;
  carrier: string;
  lineType: 'Mobile' | 'Landline' | 'VoIP' | 'Prepaid' | 'Virtual';
  location: {
    city: string;
    region: string;
    country: string;
    coordinates: { lat: number; lng: number };
    timezone: string;
  };
  reputation: {
    score: number; // 0-100
    riskLevel: 'Low' | 'Medium' | 'High' | 'Critical';
    flags: string[];
  };
  ownership: {
    name: string;
    associatedEmails: string[];
    socialPresence: string[];
  };
  summary: string;
  sources: { title: string; url: string }[];
}

export enum AnalysisStep {
  IDLE = 'IDLE',
  INITIALIZING = 'INITIALIZING',
  NETWORK_QUERY = 'NETWORK_QUERY',
  GEOLOCATION = 'GEOLOCATION',
  OSINT_SCRAPING = 'OSINT_SCRAPING',
  FINALIZING = 'FINALIZING',
  COMPLETED = 'COMPLETED',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { IntelligenceReport } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const performPhoneIntelligence = async (phoneNumber: string): Promise<IntelligenceReport> => {
  const prompt = `Perform a comprehensive digital forensic and OSINT (Open Source Intelligence) analysis on the following phone number: ${phoneNumber}.

  Your task is to identify:
  1. Primary Carrier and Line Type (e.g., Mobile, VoIP/Virtual like TextFree/Google Voice, Prepaid, Landline).
  2. Geographical location (City, State/Region, Country, approximate Coordinates).
  3. Ownership profile (Publicly available names or aliases, linked digital footprints like emails or social handles).
  4. Reputation Analysis (Spam score, fraud history, data breach presence).

  Provide a JSON response strictly following this structure:
  {
    "phoneNumber": string,
    "carrier": string,
    "lineType": "Mobile" | "Landline" | "VoIP" | "Prepaid" | "Virtual",
    "location": {
      "city": string,
      "region": string,
      "country": string,
      "coordinates": { "lat": number, "lng": number },
      "timezone": string
    },
    "reputation": {
      "score": number,
      "riskLevel": "Low" | "Medium" | "High" | "Critical",
      "flags": string[]
    },
    "ownership": {
      "name": string,
      "associatedEmails": string[],
      "socialPresence": string[]
    },
    "summary": string
  }

  Use Google Search grounding to find real-time carrier data and any public records associated with this number.
  Include URLs for sources found in the grounding Metadata.`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            phoneNumber: { type: Type.STRING },
            carrier: { type: Type.STRING },
            lineType: { type: Type.STRING },
            location: {
              type: Type.OBJECT,
              properties: {
                city: { type: Type.STRING },
                region: { type: Type.STRING },
                country: { type: Type.STRING },
                coordinates: {
                  type: Type.OBJECT,
                  properties: {
                    lat: { type: Type.NUMBER },
                    lng: { type: Type.NUMBER }
                  }
                },
                timezone: { type: Type.STRING }
              }
            },
            reputation: {
              type: Type.OBJECT,
              properties: {
                score: { type: Type.NUMBER },
                riskLevel: { type: Type.STRING },
                flags: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            },
            ownership: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                associatedEmails: { type: Type.ARRAY, items: { type: Type.STRING } },
                socialPresence: { type: Type.ARRAY, items: { type: Type.STRING } }
              }
            },
            summary: { type: Type.STRING }
          }
        }
      }
    });

    const reportData = JSON.parse(response.text || '{}');

    // Extract sources from grounding metadata
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter(chunk => chunk.web)
      ?.map(chunk => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      ...reportData,
      sources
    };
  } catch (error) {
    console.error("Intelligence acquisition failed:", error);
    throw error;
  }
};

import React, { useEffect, useState } from 'react';
import { AnalysisStep } from '../types';

interface AnalysisProgressProps {
  step: AnalysisStep;
}

const AnalysisProgress: React.FC<AnalysisProgressProps> = ({ step }) => {
  const steps = [
    { key: AnalysisStep.INITIALIZING, label: 'Initializing Secure Session' },
    { key: AnalysisStep.NETWORK_QUERY, label: 'HLR/SS7 Network Interrogation' },
    { key: AnalysisStep.GEOLOCATION, label: 'Geo-Spatial Triangulation' },
    { key: AnalysisStep.OSINT_SCRAPING, label: 'Digital Footprint Synthesis' },
    { key: AnalysisStep.FINALIZING, label: 'Compiling Intelligence Report' },
  ];

  const getCurrentIndex = () => steps.findIndex(s => s.key === step);
  const currentIndex = getCurrentIndex();

  return (
    <div className="w-full max-w-2xl mx-auto py-12 px-6">
      <div className="space-y-6">
        {steps.map((s, idx) => (
          <div key={s.key} className="relative">
            <div className={`flex items-center gap-4 transition-all duration-500 ${idx > currentIndex ? 'opacity-30' : 'opacity-100'}`}>
              <div className={`w-8 h-8 rounded-full border-2 flex items-center justify-center mono text-xs font-bold
                ${idx < currentIndex ? 'bg-emerald-500 border-emerald-500 text-black' : 
                  idx === currentIndex ? 'border-emerald-400 text-emerald-400 animate-pulse' : 'border-gray-700 text-gray-700'}`}>
                {idx < currentIndex ? '✓' : idx + 1}
              </div>
              <div className="flex-1">
                <div className={`text-sm font-medium mono ${idx === currentIndex ? 'text-emerald-400' : 'text-gray-400'}`}>
                  {s.label}
                </div>
                {idx === currentIndex && (
                  <div className="mt-2 w-full bg-gray-800 h-1 rounded-full overflow-hidden">
                    <div className="bg-emerald-500 h-full animate-[progress_2s_ease-in-out_infinite]" style={{ width: '40%' }}></div>
                  </div>
                )}
              </div>
            </div>
            {idx < steps.length - 1 && (
              <div className={`ml-4 w-px h-6 bg-gray-800 my-1 ${idx < currentIndex ? 'bg-emerald-500' : ''}`}></div>
            )}
          </div>
        ))}
      </div>

      <style>{`
        @keyframes progress {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(250%); }
        }
      `}</style>
    </div>
  );
};

export default AnalysisProgress;

import React, { useState, useEffect } from 'react';
import { IntelligenceReport, AnalysisStep } from './types';
import { performPhoneIntelligence } from './services/geminiService';
