import ReportDashboard from './components/ReportDashboard';

const App: React.FC = () => {
  const [phoneNumber, setPhoneNumber] = useState('');
  const [analysisStep, setAnalysisStep] = useState<AnalysisStep>(AnalysisStep.IDLE);
  const [report, setReport] = useState<IntelligenceReport | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!phoneNumber || phoneNumber.length < 7) {
      setError("Please enter a valid international phone number.");
      return;
    }

    setError(null);
    setAnalysisStep(AnalysisStep.INITIALIZING);

    try {
      // Simulation timings for UX "hacking" feel
      setTimeout(() => setAnalysisStep(AnalysisStep.NETWORK_QUERY), 1500);
      setTimeout(() => setAnalysisStep(AnalysisStep.GEOLOCATION), 4000);
      setTimeout(() => setAnalysisStep(AnalysisStep.OSINT_SCRAPING), 7000);
      setTimeout(() => setAnalysisStep(AnalysisStep.FINALIZING), 10000);

      const data = await performPhoneIntelligence(phoneNumber);

      // Delay completion until visual steps catch up roughly
      setTimeout(() => {
        setReport(data);
        setAnalysisStep(AnalysisStep.COMPLETED);
      }, 12000);

    } catch (err) {
      console.error(err);
      setError("Intelligence acquisition failed. The target may have advanced encryption or the carrier network rejected the probe.");
      setAnalysisStep(AnalysisStep.ERROR);
    }
  };

