              </div>
              {error && <p className="mt-4 text-red-500 mono text-xs animate-bounce">{error}</p>}
            </form>

            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-20 pt-12 border-t border-white/5 opacity-40">
              <div className="space-y-1">
                <div className="text-[10px] mono uppercase text-gray-500">VOIP DETECTION</div>
