import { GoogleGenAI, Type } from "@google/genai";
import { IntelligenceReport } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const performPhoneIntelligence = async (phoneNumber: string): Promise<IntelligenceReport> => {
  const prompt = `Perform a deep network analysis and OSINT investigation on: ${phoneNumber}.

  Focus specifically on:
  1. MOBILE CARRIER: Identify the primary network operator (e.g., Verizon, Orange, Jio, etc.).
  2. LINE CLASSIFICATION: Is it Mobile, Landline, VoIP (like TextFree, Twilio, Google Voice), Prepaid, or a Virtual number?
  3. REGIONAL ORIGIN: Determine the country and local region/state where the number was registered.
  4. IDENTITY SYNTHESIS: Find any public aliases, linked emails, or digital footprints.
  5. RISK SCORE: Evaluate if this number is associated with spam, phishing, or historical leaks.

  Provide a JSON response strictly following this structure:
  {
    "phoneNumber": string,
    "carrier": string,
    "lineType": "Mobile" | "Landline" | "VoIP" | "Prepaid" | "Virtual",
    "location": {
      "city": string,
      "region": string,
      "country": string,
      "coordinates": { "lat": number, "lng": number },
      "timezone": string
    },
    "reputation": {
      "score": number,
      "riskLevel": "Low" | "Medium" | "High" | "Critical",
      "flags": string[]
    },
    "ownership": {
