import ReportDashboard from './components/ReportDashboard';

const App: React.FC = () => {
  const [phoneNumber, setPhoneNumber] = useState('');
  const [analysisStep, setAnalysisStep] = useState<AnalysisStep>(AnalysisStep.IDLE);
  const [report, setReport] = useState<IntelligenceReport | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [logs, setLogs] = useState<string[]>([]);

  const addLog = (msg: string) => {
    setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`].slice(-6));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!phoneNumber || phoneNumber.trim().length < 7) {
      setError("Input error: target phone number format unrecognized.");
      return;
    }

    setError(null);
    setLogs([]);
    setAnalysisStep(AnalysisStep.INITIALIZING);

    try {
      // Forensic Simulation Sequence
      setTimeout(() => {
        setAnalysisStep(AnalysisStep.NETWORK_QUERY);
        addLog("Initializing SS7 secure gateway...");
        addLog("Interrogating HLR (Home Location Register)...");
      }, 1000);

      setTimeout(() => {
        setAnalysisStep(AnalysisStep.GEOLOCATION);
        addLog("Triangulating signal via cell tower metadata...");
        addLog("Resolving geographic point-of-origin...");
      }, 4000);

      setTimeout(() => {
        setAnalysisStep(AnalysisStep.OSINT_SCRAPING);
        addLog("Scraping global digital footprint repositories...");
        addLog("Searching leaked identity databases...");
      }, 7500);

      setTimeout(() => {
        setAnalysisStep(AnalysisStep.FINALIZING);
        addLog("Synthesizing forensic intelligence report...");
      }, 10500);

      const data = await performPhoneIntelligence(phoneNumber);

      setTimeout(() => {
        setReport(data);
        setAnalysisStep(AnalysisStep.COMPLETED);
      }, 12500);

    } catch (err) {
      console.error(err);
      setError("Network error: Handshake failed. Target encrypted or data restricted.");
      setAnalysisStep(AnalysisStep.ERROR);
    }
  };

  const handleReset = () => {
    setPhoneNumber('');
    setAnalysisStep(AnalysisStep.IDLE);
    setReport(null);
    setError(null);
    setLogs([]);
  };

  return (
    <div className="min-h-screen pb-24 selection:bg-emerald-500 selection:text-black">
      {/* HUD Navigation */}
      <nav className="border-b border-white/5 bg-black/60 backdrop-blur-2xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-2.5 h-2.5 bg-emerald-500 rounded-full animate-pulse shadow-[0_0_12px_#10b981]"></div>
