            <span className="hidden sm:inline-block text-[10px] mono bg-emerald-500/10 text-emerald-400 px-2 py-0.5 rounded border border-emerald-500/20 ml-2">INTEL-SYSTEM_V5.1</span>
          </div>
          <div className="flex items-center gap-8 text-[10px] mono text-gray-500 uppercase tracking-widest">
            <div className="flex items-center gap-2">
              <span className="w-1.5 h-1.5 rounded-full bg-emerald-400"></span>
              <span>Proxy_Live</span>
            </div>
            <div className="hidden md:block">
              Latency: 14ms
            </div>
          </div>
        </div>
      </nav>

      <main className="pt-16 px-6">
        {analysisStep === AnalysisStep.IDLE && (
          <div className="max-w-3xl mx-auto text-center space-y-10 animate-in fade-in slide-in-from-bottom-8 duration-1000">
            <div className="space-y-6">
              <h2 className="text-6xl md:text-7xl font-black tracking-tighter text-white leading-none">
                Identity & Origin <br/>
                <span className="text-emerald-500">Forensics</span>
              </h2>
              <p className="text-gray-400 text-lg md:text-xl max-w-xl mx-auto leading-relaxed font-light">
