              <div className="absolute -inset-1.5 bg-gradient-to-r from-emerald-500 via-emerald-400 to-blue-500 rounded-2xl blur opacity-20 group-hover:opacity-40 transition duration-1000 group-hover:duration-200"></div>
              <div className="relative glass rounded-2xl p-2.5 flex flex-col md:flex-row gap-2 shadow-2xl">
