                  placeholder="+44 7911 123456"
                  className="flex-1 bg-transparent border-0 focus:ring-0 text-xl mono text-white px-5 py-3 placeholder:text-gray-700"
                  autoFocus
                />
                <button 
                  type="submit"
                  className="bg-emerald-500 hover:bg-emerald-400 text-black font-bold mono px-10 py-3 rounded-xl transition-all hover:shadow-[0_0_25px_rgba(16,185,129,0.5)] active:scale-[0.98]"
