// Initialize AI right before call to ensure fresh environment
export const performPhoneIntelligence = async (phoneNumber: string): Promise<IntelligenceReport> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `ACT AS A SENIOR OSINT FORENSIC ANALYST.
  Interrogate target number: ${phoneNumber}

  CORE MISSION: 
  Analyze this number to reveal its true origin, carrier status, and ownership. 
  Focus specifically on identifying if this is a VoIP/Text-Free service (e.g., Google Voice, TextNow, Pinger) or a Prepaid mobile line (e.g., TracFone, Lyca).

  DATA TO CAPTURE:
  1. CARRIER: Primary MNO or Virtual Operator.
  2. LINE TYPE: Strictly classify as 'Mobile', 'Landline', 'VoIP', 'Prepaid', or 'Virtual'.
  3. LOCATION: Precise city, region, and country based on area code and public registries.
  4. OWNERSHIP: Any associated names or aliases found in public records or social leaks.
  5. IP INTEL: Any IP addresses or ISPs associated with the digital footprint of this number.
  6. TELEMETRY: Historical logs (SMS/Calls) found in spam/public datasets.

  RESPONSE RULES:
  - Return ONLY valid JSON.
  - Do NOT include markdown code blocks.
  - If data is unavailable, use "DATA_RESTRICTED" or "NO_RECORDS_FOUND".
  - Use Google Search to verify carrier ranges and recent ownership changes.

  JSON STRUCTURE:
  {
    "phoneNumber": "string",
    "carrier": "string",
    "lineType": "Mobile" | "Landline" | "VoIP" | "Prepaid" | "Virtual",
    "location": {
      "city": "string",
      "region": "string",
      "country": "string",
      "coordinates": { "lat": number, "lng": number },
      "timezone": "string"
    },
    "reputation": {
      "score": number,
      "riskLevel": "Low" | "Medium" | "High" | "Critical",
      "flags": ["string"]
    },
    "ownership": {
      "name": "string",
      "associatedEmails": ["string"],
      "socialPresence": ["string"]
    },
    "ipInfo": {
      "ipAddress": "string",
      "isp": "string",
      "location": "string"
    },
    "communicationLogs": [
      {
        "timestamp": "string",
        "type": "SMS" | "Call",
        "direction": "Incoming" | "Outgoing",
        "metadata": "string"
      }
    ],
    "summary": "string"
  }`;

  try {
    // Using Gemini 3 Pro for superior reasoning in OSINT synthesis
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 2000 } // Reserve tokens for deep analysis
      }
    });

    const responseText = response.text || '';

    // Safety check: sometimes the model might still return markdown backticks even with MimeType set
    const cleanedJson = responseText.replace(/```json/g, '').replace(/```/g, '').trim();

    const reportData = JSON.parse(cleanedJson);

    // Extract sources for transparency
    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter(chunk => chunk.web)
      ?.map(chunk => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      ...reportData,
      sources
    };
  } catch (error: any) {
    console.error("Forensic interrogation failed:", error);
    throw new Error(error.message || "Interrogation interrupted by network layer security.");
  }
};

