export const performPhoneIntelligence = async (phoneNumber: string): Promise<IntelligenceReport> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `CRITICAL OSINT INVESTIGATION: UNMASK TARGET ${phoneNumber}

  OBJECTIVE:
  1. Identify if this is a VoIP/Text-Free service (e.g., TextNow, Google Voice, Pinger, Twilio).
  2. Identify if this is a Prepaid mobile line (e.g., TracFone, Lyca, Mint).
  3. Locate the owner or the registered gateway location.
  4. Extract digital footprint (emails, social handles) linked to this specific number.

  STRICT JSON OUTPUT ONLY. NO MARKDOWN. NO BACKTICKS.

  {
    "phoneNumber": "${phoneNumber}",
    "carrier": "Primary MNO/VoIP Gateway name",
    "lineType": "Mobile" | "Landline" | "VoIP" | "Prepaid" | "Virtual",
    "location": {
      "city": "string",
      "region": "string",
      "country": "string",
      "coordinates": { "lat": number, "lng": number },
      "timezone": "string"
    },
    "reputation": {
      "score": number,
      "riskLevel": "Low" | "Medium" | "High" | "Critical",
      "flags": ["Spam", "Scam", "VoIP_Header_Detected", "Prepaid_Registry"]
    },
    "ownership": {
      "name": "Full Name or 'PROTECTED_BY_CARRIER'",
      "associatedEmails": ["string"],
      "socialPresence": ["string"]
    },
    "ipInfo": {
      "ipAddress": "Last known or related IP",
      "isp": "string",
      "location": "string"
    },
    "communicationLogs": [
      {
        "timestamp": "YYYY-MM-DD HH:mm",
        "type": "SMS" | "Call",
        "direction": "Incoming" | "Outgoing",
        "metadata": "Carrier Log Details"
      }
    ],
    "summary": "Detailed forensic synthesis focusing on user identity and device origin."
  }`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
      }
    });

    const rawText = response.text || '';

    // Aggressive JSON Cleaning: Remove markdown blocks and any trailing/leading noise
    let cleanedJson = rawText.trim();
    if (cleanedJson.startsWith('```')) {
      cleanedJson = cleanedJson.replace(/^```(?:json)?\n?/, '').replace(/\n?```$/, '');
    }

    // Final safety check for any remaining non-JSON characters
    const startIndex = cleanedJson.indexOf('{');
    const endIndex = cleanedJson.lastIndexOf('}');
    if (startIndex !== -1 && endIndex !== -1) {
      cleanedJson = cleanedJson.substring(startIndex, endIndex + 1);
    }

    const reportData = JSON.parse(cleanedJson);

    const sources = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter(chunk => chunk.web)
      ?.map(chunk => ({
        title: chunk.web!.title,
        url: chunk.web!.uri
      })) || [];

    return {
      ...reportData,
      sources
    };
  } catch (error: any) {
    console.error("Interrogation failed at the network layer:", error);
    // If it's a JSON parse error, we throw a more descriptive message
    if (error instanceof SyntaxError) {
      throw new Error("DATA_CORRUPTION: The intelligence stream was malformed. Re-attempting handshake is recommended.");
    }
    throw new Error(error.message || "Interrogation interrupted by remote host.");
  }
};

